// src/pages/DashboardPage.js
import React, { useEffect, useMemo, useState } from "react";
import { getSessions } from "../utils/firebase";
import "./DashboardPage.css";

function DonutChart({ percent }) {
  const value = Math.max(0, Math.min(100, Number(percent) || 0));
  const r = 44;
  const circ = 2 * Math.PI * r;
  const dash = (value / 100) * circ;

  return (
    <div className="db-donut">
      <svg width="116" height="116" viewBox="0 0 116 116">
        <circle cx="58" cy="58" r={r} fill="none" stroke="#ece7ff" strokeWidth="12" />
        <circle
          cx="58"
          cy="58"
          r={r}
          fill="none"
          stroke="#6b5cff"
          strokeWidth="12"
          strokeDasharray={`${dash} ${circ}`}
          strokeLinecap="round"
          transform="rotate(-90 58 58)"
        />
      </svg>

      <div className="db-donut-text">
        <span>{value}%</span>
      </div>
    </div>
  );
}

function StreakDot({ done }) {
  return (
    <div className={`db-streak-dot ${done ? "done" : "empty"}`}>
      {done && (
        <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
          <path
            d="M2 5l2 2 4-4"
            stroke="white"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      )}
    </div>
  );
}

function getSessionDate(session) {
  const rawDate =
    session?.createdAt?.toDate?.() ||
    session?.createdAt ||
    session?.date ||
    session?.timestamp?.toDate?.() ||
    session?.timestamp;

  if (!rawDate) return null;

  const parsed = new Date(rawDate);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function toDateKey(date) {
  return date.toISOString().split("T")[0];
}

function getWeeklyStreak(sessions) {
  const today = new Date();
  const dayIndex = today.getDay();
  const mondayOffset = dayIndex === 0 ? -6 : 1 - dayIndex;

  const monday = new Date(today);
  monday.setDate(today.getDate() + mondayOffset);
  monday.setHours(0, 0, 0, 0);

  const practicedDates = new Set(
    sessions
      .map(getSessionDate)
      .filter(Boolean)
      .map((date) => toDateKey(date))
  );

  const days = Array.from({ length: 7 }, (_, index) => {
    const date = new Date(monday);
    date.setDate(monday.getDate() + index);
    return practicedDates.has(toDateKey(date));
  });

  return days;
}

export default function DashboardPage({ navigate, user }) {
  const [sessions, setSessions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getSessions(50)
      .then((data) => {
        setSessions(data || []);
      })
      .finally(() => {
        setLoading(false);
      });
  }, []);

  const averageScore = useMemo(() => {
    if (!sessions.length) return 0;

    const validScores = sessions
      .map((session) => Number(session.metrics?.score ?? session.score))
      .filter((score) => !Number.isNaN(score));

    if (!validScores.length) return 0;

    return Math.round(
      validScores.reduce((total, score) => total + score, 0) / validScores.length
    );
  }, [sessions]);

  const displayName = user?.displayName || user?.email?.split("@")[0] || "Rolch Vincent Sanchez";
  const firstName = displayName.split(" ")[0];
  const initials = displayName.slice(0, 2).toUpperCase();
  const photoURL = user?.photoURL;

  const overallProgress = sessions.length ? averageScore : 69;
  const streakDays = getWeeklyStreak(sessions);
  const streakCount = streakDays.filter(Boolean).length;
  const DAYS = ["M", "T", "W", "T", "F", "S", "S"];

  return (
    <div className="db-root">
      <div className="db-main">
        <header className="db-topbar">
          <div />

          <div className="db-topbar-right">
            <button className="db-notif-btn" aria-label="Notifications">
              <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                <path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9M13.73 21a2 2 0 01-3.46 0" />
              </svg>
              <span className="db-notif-dot" />
            </button>

            <div className="db-user-pill">
              <div className="db-user-avatar">
                {photoURL ? <img src={photoURL} alt={displayName} /> : initials}
              </div>

              <div className="db-user-info">
                <span className="db-user-name">{displayName}</span>
                <span className="db-user-role">Student</span>
              </div>

              <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2" className="db-user-arrow">
                <polyline points="6 9 12 15 18 9" />
              </svg>
            </div>
          </div>
        </header>

        <main className="db-content">
          {loading ? (
            <div className="dash-loading">
              <div className="spinner" />
              <p>Loading your dashboard…</p>
            </div>
          ) : (
            <section className="db-layout">
              <div className="db-left-column">
                <div className="db-greeting">
                  <h1>Hello, {firstName}! 👋</h1>
                  <p>Ready to speak with confidence today?</p>
                </div>

                <section className="db-hero-banner">
                  <div className="db-hero-text">
                    <h2>Start a Practice Session</h2>
                    <p>
                      Choose a scenario, record your speech, and get AI-powered
                      feedback to improve.
                    </p>

                    <button className="db-hero-btn" onClick={() => navigate("practice")}>
                      Start Practice <span>→</span>
                    </button>
                  </div>

                  <div className="db-hero-art">
                    <div className="db-audio-card">
                      <div className="db-audio-bars">
                        <span />
                        <span />
                        <span />
                        <span />
                        <span />
                      </div>

                      <button className="db-audio-play" type="button">▶</button>
                    </div>

                    <div className="db-float-chip db-float-blue">≡</div>
                    <div className="db-float-chip db-float-pink">✦</div>
                    <div className="db-star db-star-one">✦</div>
                    <div className="db-star db-star-two">✦</div>
                  </div>

                  <div className="db-hero-wave">
                    <svg viewBox="0 0 600 120" preserveAspectRatio="none">
                      <path
                        d="M0 78 C95 38 160 110 270 78 C385 45 475 48 600 78 L600 120 L0 120 Z"
                        fill="rgba(255,255,255,0.08)"
                      />
                      <path
                        d="M0 98 C100 66 180 126 300 100 C420 76 510 82 600 102 L600 120 L0 120 Z"
                        fill="rgba(255,255,255,0.06)"
                      />
                    </svg>
                  </div>
                </section>

                <section className="db-tip-card">
                  <div className="db-tip-left">
                    <div className="db-tip-icon">💡</div>

                    <div className="db-tip-content">
                      <h3>Tip of the day</h3>
                      <p>
                        Pause for effect. Short pauses help your ideas land and
                        keep your listeners engaged.
                      </p>
                    </div>
                  </div>

                  <button className="db-tip-link" type="button">
                    View more tips →
                  </button>
                </section>
              </div>

              <aside className="db-right-column">
                <section className="db-widget-card db-progress-card">
                  <h3>Overall Progress</h3>

                  <div className="db-progress-body">
                    <DonutChart percent={overallProgress} />

                    <div className="db-progress-copy">
                      <h4>
                        {overallProgress >= 80
                          ? "Excellent work!"
                          : overallProgress >= 60
                          ? "You're doing great!"
                          : "Keep practicing!"}
                      </h4>
                      <p>Keep practicing to reach your goal.</p>
                    </div>
                  </div>

                  <button
                    className="db-widget-link"
                    type="button"
                    onClick={() => navigate("progress")}
                  >
                    View detailed progress →
                  </button>
                </section>

                <section className="db-widget-card db-streak-card">
                  <h3>Weekly Streak</h3>

                  <div className="db-streak-main">
                    <span className="db-fire">🔥</span>

                    <div>
                      <h4>{streakCount} days</h4>
                      <p>
                        {streakCount >= 5
                          ? "Great consistency!"
                          : streakCount >= 1
                          ? "Keep the streak going!"
                          : "Start practicing today!"}
                      </p>
                    </div>
                  </div>

                  <div className="db-streak-days">
                    {DAYS.map((day, index) => (
                      <div className="db-streak-day" key={`${day}-${index}`}>
                        <StreakDot done={streakDays[index]} />
                        <span>{day}</span>
                      </div>
                    ))}
                  </div>
                </section>
              </aside>
            </section>
          )}
        </main>
      </div>
    </div>
  );
}
